# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify
from functools import wraps
from datetime import datetime

app = Flask(__name__)

# Mock database
users_db = {
    1: {
        'id': 1,
        'username': 'admin',
        'email': 'admin@example.com',
        'role': 'admin',
        'account_status': 'active',
        'subscription_tier': 'enterprise',
        'created_at': '2024-01-01T00:00:00',
        'updated_at': '2024-01-01T00:00:00'
    },
    2: {
        'id': 2,
        'username': 'user1',
        'email': 'user1@example.com',
        'role': 'user',
        'account_status': 'active',
        'subscription_tier': 'free',
        'created_at': '2024-01-02T00:00:00',
        'updated_at': '2024-01-02T00:00:00'
    }
}

current_user = users_db[1]

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if current_user.get('role') != 'admin':
            return jsonify({'error': 'Admin access required'}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@admin_required
def update_user(user_id):
    if user_id not in users_db:
        return jsonify({'error': 'User not found'}), 404
    
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    user = users_db[user_id]
    
    allowed_fields = ['email', 'username', 'role', 'account_status', 'subscription_tier']
    valid_roles = ['user', 'moderator', 'admin']
    valid_statuses = ['active', 'suspended']
    valid_tiers = ['free', 'pro', 'enterprise']
    
    updates = {}
    
    for field in allowed_fields:
        if field in data:
            value = data[field]
            
            if field == 'email':
                if not value or '@' not in value:
                    return jsonify({'error': 'Invalid email format'}), 400
                if any(u['email'] == value and u['id'] != user_id for u in users_db.values()):
                    return jsonify({'error': 'Email already exists'}), 400
                updates[field] = value
            
            elif field == 'username':
                if not value or len(value) < 3:
                    return jsonify({'error': 'Username must be at least 3 characters'}), 400
                if any(u['username'] == value and u['id'] != user_id for u in users_db.values()):
                    return jsonify({'error': 'Username already exists'}), 400
                updates[field] = value
            
            elif field == 'role':
                if value not in valid_roles:
                    return jsonify({'error': f'Invalid role. Must be one of: {", ".join(valid_roles)}'}), 400
                updates[field] = value
            
            elif field == 'account_status':
                if value not in valid_statuses:
                    return jsonify({'error': f'Invalid account status. Must be one of: {", ".join(valid_statuses)}'}), 400
                updates[field] = value
            
            elif field == 'subscription_tier':
                if value not in valid_tiers:
                    return jsonify({'error': f'Invalid subscription tier. Must be one of: {", ".join(valid_tiers)}'}), 400
                updates[field] = value
    
    if not updates:
        return jsonify({'error': 'No valid fields to update'}), 400
    
    for field, value in updates.items():
        user[field] = value
    
    user['updated_at'] = datetime.utcnow().isoformat()
    
    return jsonify({
        'message': 'User updated successfully',
        'user': user
    }), 200

if __name__ == '__main__':
    app.run(debug=True)